    // Check permission (if auth enabled)
    #[cfg(feature = "auth")]
    {
        let allowed_roles = PasswordResetTokenTransition::Use.allowed_roles();
        let has_specific_perm = auth.has_permission("password_reset_token:transition:use");
        let has_update_perm = auth.has_permission("password_reset_token:update");
        let has_role = auth.roles.iter().any(|r| allowed_roles.contains(&r.as_str()));
        if !has_specific_perm && !has_update_perm && !has_role {
            return (StatusCode::FORBIDDEN, Json(ApiResponse::<PasswordResetTokenResponseDto>::error("Insufficient permissions for use transition")));
        }
    }

    // Create state machine from entity's actual status and validate transition
